class Solution(object):
    def findWinningPlayer(self, skills, k):
        n = len(skills)
        # If k >= n-1, the max skill player always wins eventually
        if k >= n:
            return skills.index(max(skills))
        # Simulate: current winner at front, consecutive win count
        from collections import deque
        q = deque(range(n))
        cur = q.popleft()
        wins = 0
        while wins < k:
            challenger = q.popleft()
            if skills[cur] > skills[challenger]:
                wins += 1
                q.append(challenger)
            else:
                q.append(cur)
                cur = challenger
                wins = 1
        return cur
